__device__ int addOffset(volatile uint *s_offset, uint data, uint threadTag){
    uint count;

    do{
        count = s_offset[data] & 0x07FFFFFFU;
        count = threadTag | (count + 1);
        s_offset[data] = count;
    }while(s_offset[data] != count);

    return (count & 0x07FFFFFFU) - 1;
}

__global__ void
bucketcount( float *input, int *indice, uint *d_prefixoffsets, const int size, float *l_pivotpoints)
{

	volatile __shared__ uint s_offset[BUCKET_BLOCK_MEMORY];

    const uint threadTag = threadIdx.x << (32 - BUCKET_WARP_LOG_SIZE);
    const int warpBase = (threadIdx.x >> BUCKET_WARP_LOG_SIZE) * DIVISIONS;
    const int numThreads = blockDim.x * blockDim.y * blockDim.z;
	for (int i = threadIdx.x; i < BUCKET_BLOCK_MEMORY; i += blockDim.x)
		s_offset[i] = 0;

    __syncwarp();
    __syncthreads();

	for (int tid = blockIdx.x * blockDim.x + threadIdx.x; tid < size; tid += numThreads) {
		float elem = input[tid];

		int idx  = DIVISIONS/2 - 1;
		int jump = DIVISIONS/4;
		float piv = l_pivotpoints[idx]; 

		while(jump >= 1){
			idx = (elem < piv) ? (idx - jump) : (idx + jump);
			piv = l_pivotpoints[idx]; 
			jump /= 2;
		}
		idx = (elem < piv) ? idx : (idx + 1);

		indice[tid] = (addOffset(s_offset + warpBase, idx, threadTag) << LOG_DIVISIONS) + idx;  
	}

    __syncwarp();
    __syncthreads();

	int prefixBase = blockIdx.x * BUCKET_BLOCK_MEMORY;

	for (int i = threadIdx.x; i < BUCKET_BLOCK_MEMORY; i += blockDim.x)
		d_prefixoffsets[prefixBase + i] = s_offset[i] & 0x07FFFFFFU;
}

__global__ void bucketprefixoffset(uint *d_prefixoffsets, uint *d_offsets, const int blocks) {
	int tid = blockIdx.x * blockDim.x + threadIdx.x;
	int size = blocks * BUCKET_BLOCK_MEMORY;
